package com.pedrodalben.bigbangeventos.api;
import com.pedrodalben.bigbangeventos.core.EventEngine; import com.pedrodalben.bigbangeventos.definition.EventDefinition; import com.pedrodalben.bigbangeventos.session.EventSession; import java.util.*;
public final class BigBangEventosApi { private final EventEngine engine; public BigBangEventosApi(EventEngine engine){this.engine=engine;} public Optional<EventDefinition> findEvent(String id){return engine.definition(id);} public Collection<EventDefinition> getEvents(){return engine.definitions();} public Optional<EventSession> getActiveSession(String id){return engine.activeSession(id);} public Optional<EventSession> getSessionByPlayer(UUID id){return engine.sessionByPlayer(id);} public OperationResult openRegistration(String id){return engine.open(id,null);} public OperationResult joinEvent(UUID player,String event){return engine.join(event,player,player.toString(),false,true);} public OperationResult leaveEvent(UUID player){return engine.leave(player,"api");} public OperationResult finishEvent(String id){return engine.finish(id);} public OperationResult cancelEvent(String id,String reason){return engine.cancel(id,reason);} }
